  "auth.errExists": { "zh-CN": "该邮箱已注册，请直接登录", "zh-TW": "該郵箱已註冊，請直接登入", en: "Email already registered — sign in instead", fr: "E-mail déjà inscrit — connectez-vous", ja: "このメールは登録済みです。ログインしてください", ko: "이미 가입된 이메일입니다. 로그인하세요", es: "Correo ya registrado: inicia sesión", ru: "Почта уже зарегистрирована — войдите", de: "E-Mail bereits registriert — bitte anmelden" },
