  "auth.errGeneric": { "zh-CN": "出错了，请重试", "zh-TW": "出錯了，請重試", en: "Something went wrong — try again", fr: "Une erreur s'est produite — réessayez", ja: "エラーが発生しました。再試行してください", ko: "문제가 발생했어요. 다시 시도하세요", es: "Algo salió mal: inténtalo de nuevo", ru: "Что-то пошло не так — повторите", de: "Etwas ist schiefgelaufen — erneut versuchen" },
  "set.eyebrow": { "zh-CN": "接入 · 订阅 · 语言", "zh-TW": "接入 · 訂閱 · 語言", en: "Connections · Plan · Language", fr: "Connexions · Abonnement · Langue", ja: "接続 · プラン · 言語", ko: "연결 · 플랜 · 언어", es: "Conexiones · Plan · Idioma", ru: "Подключения · План · Язык", de: "Verbindungen · Tarif · Sprache" },
  "set.lead": { "zh-CN": "应用怎么运行在这里配：AI 接入、Telos Pro、本地备份、界面语言。学习项目在「我」页管理。", "zh-TW": "應用怎麼運行在這裡設定：AI 接入、Telos Pro、本地備份、介面語言。學習專案在「我」頁管理。", en: "How the app runs: AI connections, Telos Pro, local backup, language. Manage projects on the Me page.", fr: "Le fonctionnement de l'app : connexions IA, Telos Pro, sauvegarde locale, langue. Gérez les projets sur la page Moi.", ja: "アプリの動作設定：AI 接続・Telos Pro・ローカルバックアップ・言語。プロジェクト管理は「マイ」ページで。", ko: "앱 동작 설정: AI 연결 · Telos Pro · 로컬 백업 · 언어. 프로젝트는 나 페이지에서 관리.", es: "Cómo funciona la app: conexiones IA, Telos Pro, respaldo local, idioma. Gestiona proyectos en la página Yo.", ru: "Настройки приложения: подключения ИИ, Telos Pro, локальный бэкап, язык. Проекты — на странице «Я».", de: "App-Einstellungen: KI-Verbindungen, Telos Pro, lokales Backup, Sprache. Projekte auf der Ich-Seite verwalten." },
  "set.endpoint": { "zh-CN": "接入状态", "zh-TW": "接入狀態", en: "Connections", fr: "Connexions", ja: "接続状態", ko: "연결 상태", es: "Conexiones", ru: "Подключения", de: "Verbindungen" },
  "set.endpointHint": { "zh-CN": "Telos 靠一个 AI 引擎运转；联网搜索可选，能让学习路径更贴近真实资料。", "zh-TW": "Telos 靠一個 AI 引擎運轉；聯網搜尋可選，讓學習路徑更貼近真實資料。", en: "Telos runs on an AI engine; web search is optional and grounds paths in real sources.", fr: "Telos fonctionne avec un moteur IA ; la recherche web est optionnelle et ancre les parcours dans de vraies sources.", ja: "Telos は AI エンジンで動きます。ウェブ検索は任意で、学習経路を実資料に近づけます。", ko: "Telos는 AI 엔진으로 작동합니다. 웹 검색은 선택이며 학습 경로를 실제 자료에 가깝게 합니다.", es: "Telos funciona con un motor de IA; la búsqueda web es opcional y ancla las rutas en fuentes reales.", ru: "Telos работает на AI-движке; веб-поиск опционален и привязывает пути к реальным источникам.", de: "Telos läuft mit einer KI-Engine; Websuche ist optional und verankert Pfade in echten Quellen." },
  "conn.aiTitle": { "zh-CN": "AI 引擎", "zh-TW": "AI 引擎", en: "AI engine", fr: "Moteur IA", ja: "AI エンジン", ko: "AI 엔진", es: "Motor de IA", ru: "AI-движок", de: "KI-Engine" },
  "conn.aiSub": { "zh-CN": "倒推、微课、诊断的核心", "zh-TW": "倒推、微課、診斷的核心", en: "Powers derivation, lessons & diagnosis", fr: "Au cœur de la décomposition, des leçons et du diagnostic", ja: "逆算・ミニ講義・診断の中核", ko: "역설계·미니강의·진단의 핵심", es: "Motor de derivación, lecciones y diagnóstico", ru: "Основа разбора, уроков и диагностики", de: "Kern für Ableitung, Lektionen & Diagnose" },
  "conn.searchTitle": { "zh-CN": "联网搜索", "zh-TW": "聯網搜尋", en: "Web search", fr: "Recherche web", ja: "ウェブ検索", ko: "웹 검색", es: "Búsqueda web", ru: "Веб-поиск", de: "Websuche" },
  "conn.searchSub": { "zh-CN": "为路径接入真实资料（可选）", "zh-TW": "為路徑接入真實資料（可選）", en: "Grounds paths in real sources (optional)", fr: "Ancre les parcours dans de vraies sources (optionnel)", ja: "学習経路を実資料に接続（任意）", ko: "학습 경로를 실제 자료에 연결(선택)", es: "Ancla las rutas en fuentes reales (opcional)", ru: "Привязывает пути к реальным источникам (опц.)", de: "Verankert Pfade in echten Quellen (optional)" },
