  "set.lang": { "zh-CN": "界面语言", "zh-TW": "介面語言", en: "Language", fr: "Langue", ja: "表示言語", ko: "언어", es: "Idioma", ru: "Язык", de: "Sprache" },
  "set.noBackup": { "zh-CN": "还没有项目可备份", "zh-TW": "還沒有專案可備份", en: "No project to back up yet", fr: "Aucun projet à sauvegarder", ja: "バックアップするプロジェクトがありません", ko: "백업할 프로젝트가 없습니다", es: "Aún no hay proyecto que respaldar", ru: "Пока нет проекта для копии", de: "Noch kein Projekt zum Sichern" },
  "set.backupMade": { "zh-CN": "已生成备份码 —— 复制保存，换设备粘贴导入即可", "zh-TW": "已產生備份碼 —— 複製保存，換裝置貼上匯入即可", en: "Backup code ready — copy it, paste to import on another device", fr: "Code prêt — copiez-le, collez pour importer ailleurs", ja: "バックアップコード生成 —— コピーして別端末で貼り付け取込", ko: "백업 코드 생성 — 복사해 다른 기기에서 가져오기", es: "Código listo — cópialo y pégalo en otro dispositivo", ru: "Код готов — скопируйте и вставьте на другом устройстве", de: "Backup-Code bereit — auf anderem Gerät einfügen" },
