  "lr.labelRetrieve": { "zh-CN": "检验 —— 答对即掌握", "zh-TW": "檢驗 —— 答對即掌握", en: "Recall — get it right to master", fr: "Test — réussissez pour maîtriser", ja: "検証 —— 正解で習得", ko: "검증 — 맞히면 마스터", es: "Comprueba — acierta para dominar", ru: "Проверка — верный ответ = освоено", de: "Abruf — richtig = beherrscht" },
  "lr.labelPredict": { "zh-CN": "先猜一猜（不计分）", "zh-TW": "先猜一猜（不計分）", en: "Take a guess (not scored)", fr: "Devinez (sans note)", ja: "まず予想（採点なし）", ko: "추측해보기 (점수 없음)", es: "Adivina (sin puntuar)", ru: "Угадайте (без оценки)", de: "Rate mal (zählt nicht)" },
  "lr.hintN": { "zh-CN": "提示 {n}", "zh-TW": "提示 {n}", en: "Hint {n}", fr: "Indice {n}", ja: "ヒント {n}", ko: "힌트 {n}", es: "Pista {n}", ru: "Подсказка {n}", de: "Tipp {n}" },
  "lr.submitGuess": { "zh-CN": "提交我的猜测", "zh-TW": "提交我的猜測", en: "Submit my guess", fr: "Valider ma réponse", ja: "予想を送信", ko: "내 추측 제출", es: "Enviar mi respuesta", ru: "Отправить догадку", de: "Vermutung absenden" },
  "lr.submitRetry": { "zh-CN": "看提示，再试一次", "zh-TW": "看提示，再試一次", en: "See hint, try again", fr: "Voir l'indice, réessayer", ja: "ヒントを見て再挑戦", ko: "힌트 보고 다시 시도", es: "Ver pista, reintentar", ru: "Подсказка, ещё раз", de: "Tipp ansehen, nochmal" },
  "lr.predictAnswer": { "zh-CN": "正确答案是 {letter}。{reveal}", "zh-TW": "正確答案是 {letter}。{reveal}", en: "The answer is {letter}. {reveal}", fr: "La réponse est {letter}. {reveal}", ja: "正解は {letter} です。{reveal}", ko: "정답은 {letter}입니다. {reveal}", es: "La respuesta es {letter}. {reveal}", ru: "Правильный ответ — {letter}. {reveal}", de: "Die Antwort ist {letter}. {reveal}" },
  "lr.correct": { "zh-CN": "答对了！", "zh-TW": "答對了！", en: "Correct!", fr: "Correct !", ja: "正解！", ko: "정답!", es: "¡Correcto!", ru: "Верно!", de: "Richtig!" },
  "lr.seeAnswer": { "zh-CN": "看正确答案：", "zh-TW": "看正確答案：", en: "Here's the answer:", fr: "Voici la réponse :", ja: "正解はこちら：", ko: "정답은:", es: "Aquí está la respuesta:", ru: "Вот ответ:", de: "Hier die Antwort:" },
