  "me.backupTitle": { "zh-CN": "本地备份（备份码）", "zh-TW": "本地備份（備份碼）", en: "Local backup (code)", fr: "Sauvegarde locale (code)", ja: "ローカルバックアップ（コード）", ko: "로컬 백업(코드)", es: "Respaldo local (código)", ru: "Локальный бэкап (код)", de: "Lokales Backup (Code)" },
  "me.backupNote": { "zh-CN": "导出当前项目为「备份码」，换设备粘贴导入即可，无需联网。", "zh-TW": "匯出目前專案為「備份碼」，換裝置貼上匯入即可，無需連網。", en: "Export the current project as a backup code, paste to import on another device — no network needed.", fr: "Exportez le projet en code de sauvegarde, collez pour importer sur un autre appareil — sans réseau.", ja: "現在のプロジェクトを「バックアップコード」として書き出し、別端末で貼り付けて取り込めます（ネット不要）。", ko: "현재 프로젝트를 백업 코드로 내보내 다른 기기에 붙여넣어 가져옵니다 — 네트워크 불필요.", es: "Exporta el proyecto como código de respaldo y pégalo en otro dispositivo — sin red.", ru: "Экспортируйте проект в код резервной копии и вставьте на другом устройстве — без сети.", de: "Aktuelles Projekt als Backup-Code exportieren, auf anderem Gerät einfügen — ohne Netz." },
  "me.export": { "zh-CN": "导出", "zh-TW": "匯出", en: "Export", fr: "Exporter", ja: "書き出し", ko: "내보내기", es: "Exportar", ru: "Экспорт", de: "Export" },
  "me.import": { "zh-CN": "导入", "zh-TW": "匯入", en: "Import", fr: "Importer", ja: "取り込み", ko: "가져오기", es: "Importar", ru: "Импорт", de: "Import" },
  "me.backupPlaceholder": { "zh-CN": "备份码会显示在这里；也可粘贴备份码后点「导入」", "zh-TW": "備份碼會顯示在這裡；也可貼上備份碼後點「匯入」", en: "Backup code appears here; or paste a code and tap Import", fr: "Le code apparaît ici ; ou collez un code et touchez Importer", ja: "バックアップコードがここに表示されます。コードを貼り付けて「取り込み」も可。", ko: "백업 코드가 여기 표시됩니다; 코드를 붙여넣고 가져오기를 눌러도 됩니다", es: "El código aparece aquí; o pega uno y toca Importar", ru: "Код появится здесь; или вставьте код и нажмите Импорт", de: "Backup-Code erscheint hier; oder Code einfügen und Import tippen" },
  "me.cloudTitle": { "zh-CN": "云同步 · 开发中", "zh-TW": "雲端同步 · 開發中", en: "Cloud sync · in progress", fr: "Sync cloud · en cours", ja: "クラウド同期 · 開発中", ko: "클라우드 동기화 · 개발 중", es: "Sync en la nube · en desarrollo", ru: "Облачная синхронизация · в разработке", de: "Cloud-Sync · in Arbeit" },
  "me.cloudP": { "zh-CN": "接一个免费 Supabase 项目即可账号登录、跨设备自动同步（全程你操作，我们不存你的密钥）。", "zh-TW": "接一個免費 Supabase 專案即可帳號登入、跨裝置自動同步（全程你操作，我們不存你的密鑰）。", en: "Connect a free Supabase project for account login and automatic cross-device sync (you do it all; we never store your keys).", fr: "Connectez un projet Supabase gratuit pour la connexion et la sync automatique multi-appareils (vous gérez tout ; nous ne stockons aucune clé).", ja: "無料の Supabase プロジェクトを接続すれば、アカウントログインと端末間自動同期が可能です（操作はすべてあなた、鍵は保存しません）。", ko: "무료 Supabase 프로젝트를 연결하면 계정 로그인과 기기 간 자동 동기화가 됩니다 (모두 직접 하며, 키는 저장하지 않습니다).", es: "Conecta un proyecto gratuito de Supabase para inicio de sesión y sync automática entre dispositivos (tú lo haces todo; no guardamos tus claves).", ru: "Подключите бесплатный проект Supabase для входа и автосинхронизации между устройствами (всё делаете вы; ключи не храним).", de: "Verbinde ein kostenloses Supabase-Projekt für Login und automatische geräteübergreifende Sync (du machst alles; wir speichern keine Schlüssel)." },
  "me.cloudCta": { "zh-CN": "查看启用步骤", "zh-TW": "查看啟用步驟", en: "See setup steps", fr: "Voir les étapes", ja: "設定手順を見る", ko: "설정 단계 보기", es: "Ver los pasos", ru: "Шаги настройки", de: "Schritte ansehen" },

