  "epc.local": { "zh-CN": "本地 serve.py", "zh-TW": "本地 serve.py", en: "Local serve.py", fr: "Local serve.py", ja: "ローカル serve.py", ko: "로컬 serve.py", es: "Local serve.py", ru: "Локальный serve.py", de: "Lokal serve.py" },
