  "epc.connected": { "zh-CN": "已连接", "zh-TW": "已連線", en: "Connected", fr: "Connecté", ja: "接続済み", ko: "연결됨", es: "Conectado", ru: "Подключено", de: "Verbunden" },
  "epc.model": { "zh-CN": "· 模型 {model}", "zh-TW": "· 模型 {model}", en: "· model {model}", fr: "· modèle {model}", ja: "· モデル {model}", ko: "· 모델 {model}", es: "· modelo {model}", ru: "· модель {model}", de: "· Modell {model}" },
  "epc.keyReady": { "zh-CN": "· key 已就绪", "zh-TW": "· key 已就緒", en: "· key ready", fr: "· clé prête", ja: "· キー準備完了", ko: "· 키 준비됨", es: "· clave lista", ru: "· ключ готов", de: "· Schlüssel bereit" },
  "epc.keyMissing": { "zh-CN": "· 服务端尚未配置 key", "zh-TW": "· 伺服端尚未配置 key", en: "· server has no key yet", fr: "· le serveur n'a pas de clé", ja: "· サーバーにキー未設定", ko: "· 서버에 키 없음", es: "· el servidor no tiene clave", ru: "· на сервере нет ключа", de: "· Server hat noch keinen Schlüssel" },
  "epc.note": { "zh-CN": "你的 key 只存这台设备 + 你的账号，随请求发往倒推端点、端点不落盘，绝不进前端构建产物。本机 serve.py 用 core/.env。详见 DERIVE.md。", "zh-TW": "你的 key 只存這台裝置 + 你的帳號，隨請求發往倒推端點、端點不落盤，絕不進前端建置產物。本機 serve.py 用 core/.env。詳見 DERIVE.md。", en: "Your key is stored only on this device + your account, sent with each request to the derive endpoint (which never persists it), and never baked into the front-end build. Local serve.py uses core/.env. See DERIVE.md.", fr: "Votre clé n'est stockée que sur cet appareil + votre compte, envoyée à chaque requête vers l'endpoint (qui ne la conserve pas), jamais intégrée au build front-end. serve.py local utilise core/.env. Voir DERIVE.md.", ja: "キーは本端末＋アカウントにのみ保存され、リクエスト毎にエンドポイントへ送信（保持されません）、フロントのビルドには一切入りません。ローカル serve.py は core/.env を使用。DERIVE.md 参照。", ko: "키는 이 기기 + 계정에만 저장되고 요청마다 엔드포인트로 전송되며(엔드포인트는 저장 안 함), 프런트엔드 빌드에 들어가지 않습니다. 로컬 serve.py는 core/.env 사용. DERIVE.md 참고.", es: "Tu clave se guarda solo en este dispositivo + tu cuenta, se envía con cada petición al endpoint (que no la almacena) y nunca se incrusta en el build del front-end. serve.py local usa core/.env. Ver DERIVE.md.", ru: "Ключ хранится только на этом устройстве + в вашем аккаунте, отправляется с каждым запросом на эндпоинт (который его не сохраняет) и никогда не попадает в сборку фронтенда. Локальный serve.py использует core/.env. См. DERIVE.md.", de: "Dein Schlüssel wird nur auf diesem Gerät + deinem Konto gespeichert, pro Anfrage an den Endpoint gesendet (der ihn nicht speichert) und nie in den Front-End-Build eingebaut. Lokales serve.py nutzt core/.env. Siehe DERIVE.md." },
  "epc.needUrl": { "zh-CN": "请先填写端点地址", "zh-TW": "請先填寫端點地址", en: "Enter an endpoint URL first", fr: "Saisissez d'abord une URL d'endpoint", ja: "先にエンドポイント URL を入力", ko: "먼저 엔드포인트 URL을 입력하세요", es: "Introduce primero una URL de endpoint", ru: "Сначала укажите URL эндпоинта", de: "Zuerst eine Endpunkt-URL eingeben" },
  "epc.cantConnect": { "zh-CN": "连不上 —— 确认服务在运行、地址与端口正确", "zh-TW": "連不上 —— 確認服務在執行、地址與埠正確", en: "Can't connect — check the service is running and the URL/port are right", fr: "Connexion impossible — vérifiez que le service tourne et que l'URL/port sont corrects", ja: "接続できません ——サービスの起動と URL／ポートを確認", ko: "연결할 수 없음 — 서비스 실행 여부와 URL/포트를 확인하세요", es: "No se puede conectar — verifica que el servicio corra y la URL/puerto", ru: "Не удаётся подключиться — проверьте, запущен ли сервис и верны ли URL/порт", de: "Keine Verbindung — prüfe, ob der Dienst läuft und URL/Port stimmen" },
